var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"늦은 시간까지 고생이 많군.","JPN":"遅くまでご苦労。","ENG":"It must be hard working so late.","TWN":"都這麼晚了，辛苦了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"시니어님? 일정을 마치고 집무실로 돌아가신 줄 알았는데요?","JPN":"シニア？　スケジュールを終えて執務室にお帰りになったと思っていたのですが。","ENG":"Sir? I thought you returned to your office after finishing your schedules.","TWN":"Senior？我以為你完成日程後已經回到辦公室了呢？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"건틀렛 우승자에게 수여할 장비를 반출해야 하지 않나.","JPN":"ガントレットの優勝者に授与する装備を搬出する必要があるんだ｡","ENG":"I have to take out the gear to award the Gauntlet winner.","TWN":"呵呵，我還得把明天要頒發給優勝者的裝備拿出來。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"내일 오전 일찍 최고 관리자께서 이곳을 방문하신다고 하니, 미리 준비해 둘 수밖에.","JPN":"明日の午前、早い時間に最高管理者がこちらを訪問なさるとのことで、あらかじめ用意しないとな。","ENG":"The Supreme Administrator will be visiting early tomorrow morning, so I have no choice but to prepare beforehand.","TWN":"明天一早最高管理者就要來這裡，只能提前準備好。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"그렇군요.","JPN":"なるほど。","ENG":"I see.","TWN":"原來如此。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"병기고의 장비 반출에도 시니어 권한이 필요하니…….","JPN":"兵器庫から装備を搬出する際にもシニアの権限が必要ですからね……","ENG":"Because a Senior authority is required to take out gear from the armory...","TWN":"從兵器庫調出裝備也需要高級許可權……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"자네도 그만하고 어서 퇴근하도록 해.","JPN":"君もその辺にして、早く退勤するように。","ENG":"You should go home.","TWN":"別磨蹭了，快去下班吧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"내일부터 바빠질 지도 모르니.","JPN":"明日から忙しくなるかもしれない。","ENG":"We might be busy starting tomorrow.","TWN":"從明天開始可能會很忙。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SYS_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>2급 관리자 확인. 리하르트 베르너.</color>","JPN":"<color=#ffd34c>2級管理者を確認。リヒャルト・ベルナー。</color>","ENG":"<color=#ffd34c>Class 2 Administrator confirmed. Richard Werner</color>","TWN":"<color=#ffd34c>2級管理員確認。理查·韋爾納。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L17_1","type":"dialog","speaker":"SYS_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>병기고 접근 승인.</color>","JPN":"<color=#ffd34c>兵器庫へのアクセス承認。</color>","ENG":"<color=#ffd34c>Access granted to the armory.</color>","TWN":"<color=#ffd34c>兵器庫訪問成功。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GAME_LIFT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"리하르트 베르너…….","JPN":"リヒャルト・ベルナー……","ENG":"Richard Werner...","TWN":"理查·韋爾納……"},"stage":{"bg":"GAME_LIFT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"대정화 전쟁에 지휘관으로 참전한 당신은 어느 전투에서 패전하여 큰 부상을 입었습니다.","JPN":"大浄化戦争に指揮官として参戦したあなたは、とある戦いにて敗れ、大怪我を負いました。","ENG":"You were gravely injured after losing a battle during the Grand Purification War where you participated as a commander.","TWN":"多年前作為大淨化戰爭的指揮官參戰，在某次戰鬥中敗北，身受重傷。"},"stage":{"bg":"GAME_LIFT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"시간이 지나, 2급 관리자로 선별된 당신은 지난 날의 과오를 잊지 않겠다고 맹세했어요.","JPN":"時が流れ、2級管理者として選別されたあなたは去りゆく日の誤ちを忘れないと誓いました。","ENG":"As time passed, you vowed you'd never forget the mistakes you made in the past when you were appointed as a Class 2 Administrator.","TWN":"時光流逝，被選為2級管理員的你立下誓言，不會忘記過去所犯下的過錯。"},"stage":{"bg":"GAME_LIFT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래서 2급 관리자의 증표, <color=#ffd34c>시니어 코드</color>를 자기 의안에 심어두었죠.","JPN":"それで2級管理者の証、<color=#ffd34c>シニアコード</color>を自分の義眼に入れたのですね。","ENG":"So, you implanted the <color=#ffd34c>Senior Code</color>, the mark of a Class 2 Administrator, in your eye.","TWN":"所以，你將2級管理者的象徵，<color=#ffd34c>資深代碼</color>也植入了自己的義眼中。"},"stage":{"bg":"GAME_LIFT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"전쟁에서 잃은 눈으로 전사한 이들을 주시하며, 결코 그들을 잊지 않겠다는 맹세.","JPN":"戦争で失った目で戦死した者たちを見つめ、決して彼らを忘れないという誓い。","ENG":"Your vow to see those who died in the battle with the eye you lost in the war, and never forget about them.","TWN":"用在戰爭中失去的眼睛注視著犧牲的戰士，發誓會永遠銘記著他們。"},"stage":{"bg":"GAME_LIFT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신의 그 굳은 맹세조차도 다른 정보로 덮어씌워 잊게 만들다니.","JPN":"あなたのその固い誓いさえも、他の情報で上書きして、忘れさせてしまうなんて。","ENG":"Even your determination is rewritten with other information.","TWN":"竟然能用其他資訊覆蓋你堅定的誓言。"},"stage":{"bg":"GAME_LIFT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"정보 오염이라는 건 참으로 두렵군요.","JPN":"情報汚染というのはとても恐ろしいものです。","ENG":"Data corruption is truly scary.","TWN":"資訊污染真是可怕呢。"},"stage":{"bg":"GAME_LIFT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신은 나름대로 철저하게 행동했어요.","JPN":"あなたは、あなたなりに徹底した行動を取りました。","ENG":"In your own way, you acted meticulously.","TWN":"你做得很徹底。"},"stage":{"bg":"GAME_LIFT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신과 꽤 오래 일해왔는데, 코드 발동을 확인하지 못해 그걸 모방할 수 없었으니까요.","JPN":"あなたとはかなり長い間一緒に働いてきたんですが、コードの発動を確認できず、模倣することができませんでした。","ENG":"I have worked with you for quite some time, but I could never imitate how you activate your code for you never showed me.","TWN":"我和你共事了這麼久，卻一直沒能見到你啟動代碼，所以無法模仿它。"},"stage":{"bg":"GAME_LIFT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 그 발동을 확인한 이상…….","JPN":"ですが、その発動を確認した以上……","ENG":"But since I have now seen how it's activated...","TWN":"不過現在……"},"stage":{"bg":"GAME_LIFT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이제 이 머리는 더 이상 필요 없겠죠.","JPN":"もうこの頭は必要ありません。","ENG":"This head is no longer needed.","TWN":"既然見過了，這腦袋已經沒用了吧。"},"stage":{"bg":"GAME_LIFT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇군요, 이게 알파트릭스에서 제작한 <color=#ffd34c>유사 얼터니움 리액터</color>.","JPN":"なるほど、これがアルファトリックスで製作した<color=#ffd34c>類似オルタニウムリアクター</color>。","ENG":"So, this is the <color=#ffd34c>pseudo-Alternium Reactor</color> produced by Alphatrix.","TWN":"原來如此，這是阿爾法崔克斯製作的<color=#ffd34c>黑化永恆之金電抗器</color>。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 이건 늑대의 테크 레벨5 무장, <color=#ffd34c>도르마</color>…….","JPN":"そしてこれはオオカミのテックレベル5武装、<color=#ffd34c>ドルマ</color>……","ENG":"And this is the Wolf's Tech Level 5 gear, <color=#ffd34c>Droma</color>...","TWN":"這是狼的技術等級5武裝，<color=#ffd34c>多爾瑪</color>……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"상품으로 코핀 컴퍼니의 압류품들을 준비해두다니.","JPN":"賞品としてコフィンカンパニーの差押え品を用意するなんて。","ENG":"Preparing the awards with equipment confiscated by Coffin Company.","TWN":"竟然準備了科芬公司的扣押品作為獎品。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"역시 리하르트도 관리자의 우승을 예상하고 있었군.","JPN":"やっぱりリヒャルトも管理者の優勝を予想していたんですね。","ENG":"So Richard and the Administrator already predicted who'd be the champion.","TWN":"果然，你也預料到了管理者會獲勝。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"코러스에서 모방한 파동 확산 장치, <color=#ffd34c>컨버터</color>.","JPN":"コーラスを模倣した波動拡散装置、<color=#ffd34c>コンバーター</color>。","ENG":"An imitation of Chorus' wave amplifier, <color=#ffd34c>the converter</color>.","TWN":"從Chorus模仿來的波動擴散裝置，<color=#ffd34c>轉換器</color>。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L48_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"컨버터에 동력원을 제공해 줄 <color=#ffd34c>유사 얼터니움 리액터</color>.","JPN":"コンバーターに動力を提供する<color=#ffd34c>類似オルタニウムリアクター</color>。","ENG":"The <color=#ffd34c>pseudo-Alternium Reactor</color> provides power to the converter.","TWN":"為其提供動力的<color=#ffd34c>仿黑化永恆之金電抗器</color>。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 도르마에 묻어 있는 <color=#ffd34c>늑대의 피</color>.","JPN":"そしてドルマについている<color=#ffd34c>オオカミの血</color>。","ENG":"And the <color=#ffd34c>Wolf's blood</color> on Droma.","TWN":"還有多爾瑪上的<color=#ffd34c>狼血</color>。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래, 이 세가지가 있다면…….","JPN":"そう、この三つが揃えば……","ENG":"Yes, with these three...","TWN":"對，如果有這三樣東西的話……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"구원기사단이 그랬던 것처럼. 클리포트 인자 파동을 일으켜, <color=#ffd34c>그것</color>을 끌어들일 수도 있겠지.","JPN":"救世騎士団のように、クリフォトファクターの波動を起こして<color=#ffd34c>あれ</color>を引き寄せることができるでしょう。","ENG":"I can lure <color=#ffd34c>the one</color> by creating a Qliphoth Factor wave. Just like how the Knights of Redemption did.","TWN":"就像救贖騎士團那樣。引起逆卡巴拉因子波動，<color=#ffd34c>那個東西</color>也會被吸引過來吧。"},"stage":{"bg":"MAINSTREAM_808","bgm":"THEMA_SIXWING","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"지성을 잃고, 괴물로 전락해버린 <color=#ffd34c>거짓된 신</color>을…….","JPN":"知性を失い、化け物へと成り果ててしまった<color=#ffd34c>偽りの神</color>を……","ENG":"The <color=#ffd34c>false god</color> who lost all intelligence and was reduced to a monster...","TWN":"失去理智，墮落成怪物的<color=#ffd34c>幻神</color>……。"},"stage":{"bg":"MAINSTREAM_808","bgm":"THEMA_SIXWING","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"subtitle","speaker":null,"text":{"KOREA":"몇 시간 뒤","JPN":"数時間後","ENG":"A few hours later","TWN":"幾小時後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"오셨군요, 기다리고 있었습니다.","JPN":"ようこそ、お待ちしておりました。","ENG":"You're here. We've been waiting for you.","TWN":"您來了，Senior在辦公室等您。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"시니어님의 집무실은 안쪽입니다.","JPN":"シニアの執務室は奥の方です。","ENG":"The Senior's office is just inside.","TWN":"往裡面請。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"시니어님, 말씀하신 손님 분께서 방문하셨습니다.","JPN":"シニア、お客様がお見えになりました。","ENG":"Sir, your guest has arrived.","TWN":"Senior，您約的客人來了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"……시니어님?","JPN":"……シニア？","ENG":"...Sir?","TWN":"……Senior？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"인기척이 안 나는데, 외출한 거 아니야?","JPN":"いないみたいだけど、出かけたんじゃない？","ENG":"I don't think he's in. Did he step out for a minute?","TWN":"怎麼都沒聲音，是外出了嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"아뇨. 그럴 리가요. 일정이 생기셨다면 저한테 말씀해 주셨을 텐데…….","JPN":"いいえ、そんなはずはありません。予定ができたのであれば私にお知らせくださらないはずが……","ENG":"No, of course not. If something came up, he would've told me first...","TWN":"不，應該不是，要是有什麼行程應該會告訴我才對……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"한 번 문을 열어줄 수 있겠나?","JPN":"ドアを開けてみてもらえるかね？","ENG":"Could you open the door for us, please?","TWN":"門可以開嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"문이 잠겨 있네요.","JPN":"ドアにカギがかかっていますね。","ENG":"The door seems to be locked.","TWN":"門鎖起來了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"잠시 기다리세요. 열쇠를 가져오겠습니다.","JPN":"少々お待ちください。カギをお持ちします。","ENG":"Hold on. I'll go get the keys.","TWN":"請稍候，我去拿鑰匙。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"시, 시니어님……?","JPN":"し、シニア……？","ENG":"S-sir...?","TWN":"Senior……？"},"stage":{"bg":"CHARADE2_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L32_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"머리가…… 사라졌어? 이, 이게 대체 무슨……?","JPN":"頭部が……消えている？　こ、これはいったいどういう……？","ENG":"Where's... his head? W-what's happened to him...?","TWN":"頭……不見了？怎，怎麼會這樣……？"},"stage":{"bg":"CHARADE2_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_SMALL"},{"id":"L33_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"사장님, 이건…….","JPN":"社長、これって……","ENG":"Boss, this looks like...","TWN":"老闆，這是……"},"stage":{"bg":"CHARADE2_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"흠…….","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"CHARADE2_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"직원들에게 연락해 주게나, 미나 양.","JPN":"社員たちに連絡してくれ、ミナ君。","ENG":"Mina, go call our employees.","TWN":"米娜，幫我聯絡大家。"},"stage":{"bg":"CHARADE2_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아무래도 좀 바빠질 것 같군.","JPN":"どうやら忙しくなりそうだ。","ENG":"It looks like we'll be busy soon.","TWN":"看來之後會有點忙。"},"stage":{"bg":"CHARADE2_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"subtitle","speaker":null,"text":{"KOREA":"한 시간 뒤","JPN":"一時間後","ENG":"One hour later","TWN":"一小時後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>샤레이드</color>\\n공항, 제2 터미널","JPN":"管理局直轄都市<color=#ffd34c>シャレード</color>\\n空港、第2ターミナル","ENG":"Administration Direct Control City, <color=#ffd34c>Charade</color>\\nAirport, Terminal 2","TWN":"管理局直轄市<color=#ffd34c>查雷德</color>\\n機場，第2航站樓"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"WORKER_NPC_AIRPORT_A","text":{"KOREA":"신원 확인했습니다.","JPN":"身元を確認しました。","ENG":"Identification completed.","TWN":"已驗證身分。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"WORKER_NPC_AIRPORT_A","text":{"KOREA":"즐거운 여행되시길 바랍니다, 스완 양.","JPN":"楽しい旅行を、スワンさん。","ENG":"Have a nice trip, Miss Swan.","TWN":"旅途愉快，史旺小姐。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"네, 고마워요.","JPN":"はい、ありがとうございます。","ENG":"I will. Thank you.","TWN":"好的，謝謝。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"WORKER_NPC_AIRPORT_A","text":{"KOREA":"봤어요? 방금 나한테 웃어주는 거.","JPN":"見ました？　今私に微笑んでくれましたよ。","ENG":"Did you see that? She just smiled at me.","TWN":"你看到了嗎？她對我笑了。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L3_1","type":"dialog","speaker":"WORKER_NPC_AIRPORT_B","text":{"KOREA":"저런 유명한 사람이 매니저도 없이 혼자 움직이네요.","JPN":"あんな有名人がマネージャーもなく一人で行動することもあるんですね。","ENG":"It's odd that such a well-known person is traveling alone without a manager.","TWN":"如此出名的人身邊連一個經紀人也沒有。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"WORKER_NPC_AIRPORT_A","text":{"KOREA":"이번 작품만 끝나면 배우활동 잠시 쉴 거라고 했잖아요. 휴가라도 다녀오나 보죠.","JPN":"今の作品が終わったら、しばらく女優業は休むって言ってたじゃないですか。バカンスですかね？","ENG":"She mentioned how she was going to take a break from acting after this one, right? Maybe she's going on vacation.","TWN":"她說過拍完現在的作品後會進入休息期，應該是要去度假吧。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"WORKER_NPC_AIRPORT_B","text":{"KOREA":"로터스는 휴양지로 삼기엔 꽤 위험한 곳이지 않나요? 거기 사는 사람들도 다른 데로 이주하고 싶어서 난린데.","JPN":"ロータスって、バカンスで行くには危険でしょう？　あそこの住民だって引っ越したがってるのに。","ENG":"Isn't Lotus pretty dangerous to go on vacation, though? Even the residents there are trying their best to move away.","TWN":"去洛德斯度假是不是有些太危險了？連那裡的住民都想趕快搬到別的地區呢。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"WORKER_NPC_AIRPORT_A","text":{"KOREA":"그러니까 사람들 시선 피하기엔 딱이죠. 그동안 얼마나 많은 파파라치들에게 시달렸겠어요?","JPN":"だから人目を避けるにはうってつけなんでしょう。今までパパラッチのせいで苦労してただろうし。","ENG":"It's perfect for avoiding people. She must've struggled a lot with all the paparazzi constantly chasing her.","TWN":"所以才會更適合避開群眾視線，她一定受夠了狗仔隊。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WORKER_NPC_AIRPORT_B","text":{"KOREA":"이 사람… 완전히 빠졌구만.","JPN":"この人……完全にファンだな。","ENG":"You're... really smitten, aren't you?","TWN":"你這傢伙……完全迷上她咧。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"네, 대장님.","JPN":"はい、隊長。","ENG":"Yes, Commander.","TWN":"你好，隊長。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"어라?","JPN":"あれ？","ENG":"Oh?","TWN":"咦？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"당연히 안 받을 줄 알았는데, 의외의 반응이네요.","JPN":"絶対に出ないと思ってたのに、意外ですね。","ENG":"I didn't think you'd pick up. This is unexpected.","TWN":"我還以為你肯定不會接呢，真出乎意料。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"뻔뻔하게 전화를 거셨으니, 저도 뻔뻔하게 받은 것뿐인 걸요.","JPN":"図々しく電話をかけてきましたので、私も図々しく出ただけです。","ENG":"Well, you were shameless enough to call, so I am being shameless and picking up.","TWN":"你厚著臉皮打了電話，我就厚著臉皮接了。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저와 무슨 대화가 하고 싶은 거죠?","JPN":"なにか私に用件ですか？","ENG":"What did you want to talk about?","TWN":"你想和我談什麼？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"아주 요란스럽게 일을 벌이고 떠났더군요.","JPN":"また盛大にやってくれましたね。","ENG":"You really stirred things up before you left.","TWN":"我看你惹出了不少麻煩呢。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"샤레이드의 시니어를 그런 식으로 처리할 줄은 몰랐어요.","JPN":"シャレードのシニアをあんなふうに処理するとは思いませんでした。","ENG":"I never expected you to take care of Charade's Senior in that manner.","TWN":"沒想到會以那種方式處理查雷德的Senior。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저는 누군가 제 뒤를 캐는 걸 별로 좋아하지 않거든요.","JPN":"私は誰かに調査されるのが、好きではありませんので。","ENG":"I'm not a fan of people prying on me.","TWN":"因為我不喜歡有人在背後摸我底細。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신을 따르는 그 새침데기 리트리버도 마찬가지고요.","JPN":"あなたに従うあのすましたレトリーバーもそうです。","ENG":"Including that coy little retriever of yours.","TWN":"你那隻裝模作樣的獵犬也一樣。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"제법 감정적이시네요. 저희가 스완 씨의 심기를 제대로 거슬렀나 봐요.","JPN":"思ったより感情的なんですね。僕たちがスワンさんの機嫌を損ねてしまったようです。","ENG":"You're quite emotional. We must've upset you deeply.","TWN":"你似乎很激動，我們是不是惹你生氣了。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"모든 것은 예정된 전개예요. 제 감정은 한 번도 각본을 벗어난 적이 없습니다.","JPN":"すべて予想された展開でした。私の感情は一度も脚本から外れたことはありません。","ENG":"Everything is according to plan. My emotions have never strayed from the script.","TWN":"一切都是事先安排好的。我的情緒從來沒有脫離過劇本。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하지만, 그 대답을 듣고도 잘 이해가 안 되는 부분이 있어요.","JPN":"そうでしょうか？　でも、気になるところがあります。","ENG":"But that answer is still not enough to help me understand this one thing.","TWN":"不過，我對這個答案還是有些不太理解。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"당신은 분명 그날 최고관리자님의 정체를 알아봤을 텐데요.","JPN":"あなたは確かにあの日、最高管理者さんの正体を知ったはずです。","ENG":"I'm sure you recognized the Supreme Administrator's identity that day.","TWN":"你那天一定認出了最高管理者的真實身分。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"관리자님을 노리는 건, 보안을 뚫고 그 시니어를 처리하는 것보다 쉬운 일이었겠죠. 그렇지 않나요?","JPN":"管理者さんを狙うのは、保安を突破してあのシニアを処理することより簡単だった。違いますか？","ENG":"Going for the Administrator would've been easier than going through all that security to eliminate the Senior, am I wrong?","TWN":"與其突破保全處理Senior，直接對管理者下手應該更容易不是嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후훗, 모든 걸 알고 있는 양 말하던 당신도… 지금은 호기심 많은 아이일 뿐이군요.","JPN":"ふふっ、すべてを知っているかのように話していたあなたも……今では好奇心旺盛な子ども同然ですね。","ENG":"Fu fuu, you used to act like you knew everything... and now you're just another child, full of curiosity.","TWN":"呵呵，你雖然一副什麼都知道的語氣……但其實你也是一個充滿好奇心的孩子而已。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제가 원하지 않았다. 그 정도 설명으론 부족할까요?","JPN":"私がそれを望んでいなかった。この説明で納得していただけるでしょうか？","ENG":"I didn't want to. Is that enough of a reason for you?","TWN":"我並不想這麼做。這個理由充分嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"당신이 그토록 찾았고, 당신의 각본에 걸림돌이 될 게 뻔한 존재일 텐데요?","JPN":"あなたがあんなにも探し求め、恐らくあなたの脚本の邪魔になる存在なのにですか？","ENG":"You were looking for him so hard, and he's sure to be an obstacle in your play.","TWN":"那是你一直在追尋的，會成為你的劇本當中的絆腳石的人。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"괜찮아요.","JPN":"ええ。","ENG":"It's fine.","TWN":"無所謂。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"전 오히려 그 사람이 살아서 봐줬으면 하거든요.","JPN":"私はむしろ、あの人に生きて見届けてもらいたいのです。","ENG":"I'd prefer him to survive and watch.","TWN":"我寧願他活著看到這一切。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제가 곧 이뤄내게 될 일들을.","JPN":"もうすぐ私が成し遂げることを。","ENG":"Watch the things I'm about to accomplish.","TWN":"看到我將實現的一切目標。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이번엔 제가 하나 물어봐도 될까요, 대장님?","JPN":"今度は私から質問してもよろしいでしょうか？　隊長。","ENG":"I'd like to ask a question now, Commander.","TWN":"這次我能問你一個問題嗎，隊長？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"지금부터 우리가 하게 되는 건… 스릴 넘치는 추격전일까요? 아니면 미스터리 범죄일까요?","JPN":"今から私たちが行うのは……スリル溢れる追撃戦でしょうか？　それともミステリー犯罪でしょうか？","ENG":"Which one are we about to experience...? A thrilling chase? Or a mystery crime?","TWN":"我們即將展開的……是充滿刺激的追擊戰？還是犯罪懸疑片？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"아쉽게도 이번엔 제가 맡을 배역은 없습니다.","JPN":"残念ですが、今回私に配役はありません。","ENG":"Unfortunately, I won't be playing any role this time.","TWN":"很遺憾，這次我不會扮演任何角色。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"당신의 실수가 결정적인 순간 발목을 잡을 테니까요.","JPN":"あなたの失敗が、決定的な瞬間に足を引っ張るはずなので。","ENG":"Your mistake will come and haunt you at the most inconvenient moment.","TWN":"你的失誤會在關鍵時刻拖住你的腳步。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"설마, 자기 혼자선 아무것도 못하는 그 사람이 제 앞을 막을 수 있을 거라고 생각하나요?","JPN":"まさか、自分一人では何もできないあの人が私の行く手を阻めるとお思いで？","ENG":"Do you think he can get in my way? You know he can't do anything by himself.","TWN":"你真的認為那個憑自己什麼都做不到的傢伙能阻止我嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L47_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"당신은 참 실력이 뛰어난 배우예요, 스완 양.","JPN":"スワンさん、あなたは素晴らしい女優です。","ENG":"You're a very talented actress, Swan.","TWN":"你是個非常出色的演員，史旺。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"어떤 조건 속에서도 뛰어난 작품을 만드는 데 실패한 적이 없으니까요.","JPN":"どんな条件下でも素敵な作品を作りあげてきた。","ENG":"You've never failed to give an amazing performance, no matter the circumstances.","TWN":"在任何情況下都能創作出優秀的作品。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하지만 명작이란 건 원래… 배우 혼자 만들어내는 게 아니잖아요?","JPN":"ですが、名作とは本来……女優一人の力でできるものではないでしょう？","ENG":"But a masterpiece... isn't created by an actress alone.","TWN":"但一部傑作……不可能只有演員獨自一人完成不是嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇다면 두고 보죠.","JPN":"それでは見届けましょう。","ENG":"Then we shall see.","TWN":"那我們拭目以待吧。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이 믿고 있는 그 대단한 감독이…","JPN":"あなたが信じるあの大監督が……","ENG":"If that great director you trust so dearly...","TWN":"你寄予厚望的大導演……"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"배우에게서 스포트라이트를 빼앗아갈 수 있을지.","JPN":"女優からスポットライトを奪えるかどうか。","ENG":"Can steal the spotlight from an actress.","TWN":"究竟是否能將演員身上的聚光燈奪走。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};